const { ApolloServer, gql, PubSub } = require('apollo-server-express');
const express = require('express');
const { createServer } = require('http');
const { execute, subscribe } = require('graphql');
const { SubscriptionServer } = require('subscriptions-transport-ws');
const { createHash } = require('crypto');

const pubsub = new PubSub();
const ROOMS = new Set();
const USERS = new Map();

const typeDefs = gql`
  type Message {
    id: ID!
    content: String!
    author: String!
    roomId: String!
    timestamp: String!
  }

  type Query {
    messages(roomId: String!): [Message!]!
  }

  type Subscription {
    messageAdded(roomId: String!): Message!
  }

  type Mutation {
    sendMessage(roomId: String!, content: String!, author: String!): Message!
  }
`;

const resolvers = {
  Query: {
    messages: (parent, args, context) => {
      const { roomId } = args;
      if (!roomId || typeof roomId !== 'string') {
        throw new Error('Invalid room ID');
      }
      return Array.from(USERS.values())
        .filter(user => user.roomId === roomId)
        .map(user => ({
          id: user.id,
          content: user.content,
          author: user.author,
          roomId: user.roomId,
          timestamp: user.timestamp
        }));
    }
  },
  Mutation: {
    sendMessage: (parent, args, context) => {
      const { roomId, content, author } = args;
      
      if (!roomId || typeof roomId !== 'string' || roomId.length > 100) {
        throw new Error('Invalid room ID');
      }
      
      if (!content || typeof content !== 'string' || content.length > 1000) {
        throw new Error('Invalid message content');
      }
      
      if (!author || typeof author !== 'string' || author.length > 50) {
        throw new Error('Invalid author name');
      }

      const message = {
        id: createHash('sha256').update(`${roomId}-${Date.now()}-${Math.random()}`).digest('hex'),
        content,
        author,
        roomId,
        timestamp: new Date().toISOString()
      };

      pubsub.publish(`MESSAGE_ADDED_${roomId}`, { messageAdded: message });
      return message;
    }
  },
  Subscription: {
    messageAdded: {
      subscribe: (parent, args, context) => {
        const { roomId } = args;
        if (!roomId || typeof roomId !== 'string') {
          throw new Error('Invalid room ID');
        }
        return pubsub.asyncIterator(`MESSAGE_ADDED_${roomId}`);
      }
    }
  }
};

const server = new ApolloServer({
  typeDefs,
  resolvers,
  context: ({ req }) => {
    return {
      user: req.user || null
    };
  },
  introspection: true,
  playground: true,
  plugins: [{
    serverWillStart() {
      return {
        async drainServer() {
          // Cleanup logic if needed
        }
      };
    }
  }]
});

const app = express();

server.start().then(() => {
  server.applyMiddleware({ app, path: '/graphql' });
  
  const httpServer = createServer(app);
  
  const subscriptionServer = SubscriptionServer.create(
    {
      schema: server.schema,
      execute,
      subscribe,
      onConnect: (connectionParams, webSocket, context) => {
        return { pubsub };
      }
    },
    {
      server: httpServer,
      path: '/graphql'
    }
  );
  
  const PORT = process.env.PORT || 4000;
  httpServer.listen(PORT, () => {
    console.log(`🚀 Server ready at http://localhost:${PORT}${server.graphqlPath}`);
    console.log(`🚀 Subscriptions ready at ws://localhost:${PORT}${server.graphqlPath}`);
  });
});